INSERT INTO public.assessment_components (id, description, name) VALUES (1, NULL, 'Aktīvs darbs nodarbībās') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_components (id, description, name) VALUES (6, 'Rakstiskā formā sagatavots pārskats par darba autora patstāvīgi veiktu uzdevumu, lai padziļināti iepazītos ar kādu no attiecīgā studiju kursa daļām, izziņas procesa gaitu, izklāstot iegūtos rezultātus objektīvā, zinātniskiem pētījumiem raksturīgā formā.', 'Kursa projekts') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_components (id, description, name) VALUES (7, 'Zinātniski pētniecisks, docētāja pārraudzībā veikts praktisks izpētes darbs, kura laikā praktiski (vai teorētiski modelējot) tiek atrisināts kāds jautājums, analizēti iegūtie rezultāti un izdarīti secinājumi.', 'Laboratorijas darbs') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_components (id, description, name) VALUES (3, 'Mācību darba veids teorētisko zināšanu, prasmju un iemaņu nostiprināšanai individuāli vai grupā.', 'Praktiskais darbs') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_components (id, description, name) VALUES (8, 'Rakstveida studiju rezultātu daļas pārbaude studiju kursā.', 'Kontroldarbs') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_components (id, description, name) VALUES (5, 'Eksāmens, ieskaite vai cits pārbaudījums atbilstoši kursa aprakstam', 'Kursa noslēguma pārbaudījums') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_components (id, description, name) VALUES (9, 'Samērā plaša publiska runa, tostarp arī tās rakstveida teksts, kurā, parasti koncentrētā veidā, ietverti faktu, darbību, notikumu, problēmu analīzes un izpētes rezultāti, vispārinājumi, secinājumi, ieteikumi un prognozes.', 'Referāts') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_components (id, description, name) VALUES (4, 'Attiecīgajā studiju kursā veikts pētījums, kurā studējošie analizē situāciju vai problēmu, izdara secinājumus un izstrādā priekšlikumus savā darbā apskatīto jautājumu īstenošanai vai problēmu risināšanai.', 'Studiju darbs') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_components (id, description, name) VALUES (10, 'Standartizēts uzdevums vai uzdevumu kopums, pēc kuru izpildes rezultātiem vērtē studējošā spējas, zināšanas un iemaņas.', 'Tests') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_forms (id, description, name) VALUES (1, 'Studējošā studiju rezultātu (zināšanu, prasmju un kompetenču) sasniegšanas pakāpes pārbaudes veids, kurā vērtējums tiek noteikts, izmantojot 10 ballu sistēmu.', 'Eksāmens') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_forms (id, description, name) VALUES (2, 'Akadēmiskās bakalaura vai maģistra studiju programmas noslēguma pārbaudījums, kas ietver bakalaura vai maģistra darba izstrādi un aizstāvēšanu.akadēmiskās bakalaura vai maģistra studiju programmas noslēguma pārbaudījums, kas ietver bakalaura vai maģistra darba izstrādi un aizstāvēšanu.', 'Gala pārbaudījums') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_forms (id, description, name) VALUES (3, 'Studējošā studiju rezultātu (zināšanu, prasmju un kompetences) sasniegšanas pakāpes pārbaudes veids, ko vērtē ar “ieskaitīts” vai “neieskaitīts”.studējošā studiju rezultātu (zināšanu, prasmju un kompetences) sasniegšanas pakāpes pārbaudes veids, ko vērtē ar “ieskaitīts” vai “neieskaitīts”.', 'Ieskaite') ON CONFLICT DO NOTHING;
INSERT INTO public.assessment_forms (id, description, name) VALUES (5, 'Pārbaudījums, kurā vērtē gan studējošā mutvārdu atbildes, gan rakstveidā izpildītus uzdevumus, kurā vērtējums tiek noteikts, izmantojot 10 ballu sistēmu. Mutvārdu un rakstveida daļu īpatsvars pārbaudījumā tiek noteikts studiju kursa aprakstā.', 'Kombinētais pārbaudījums') ON CONFLICT DO NOTHING;
