INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('f4130627-2843-4013-9152-bf41317d7ae3', 0, NULL, '2026-04-04 20:23:51.526716', NULL, NULL, 0, 'lv', NULL, NULL, NULL, NULL, NULL, 'abea04d9-aae8-4457-b88a-7dcb37a30053', 'cf53046f-6dbe-430a-92a6-2ead4daf38d3', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('884291a6-0809-44cc-826c-d3c28ab24b39', 32, 'Kurss sastāv no teorijas lekcijām, kas sniedz vispārīgu un aktuālu informāciju par svarīgākajām datora sastāvdaļām ar vēsturisko kontekstu un īpašu uzsvaru uz centrālā procesora darbības pamatprincipiem. Savukārt laboratorijas darbu ietvaros studenti apgūst tādas ar datorsistēmu uzturēšanu saistītas prasmes kā datora izjaukšana/salikšana, operētājsistēmu instalēšana, diska partīciju izveide un klonēšana, tīkla konfigurācija utt.', '2026-05-03 00:19:48.496377', NULL, 'Kursa mērķis ir sniegt vispārīgu informāciju par svarīgākajām datora sastāvdaļām – centrālo procesoru un tā darbības principiem, dažādiem atmiņas veidiem un citu svarīgāko perifēriju, kā arī apgūt praktiskas iemaņas darbā ar datorsistēmu uzturēšanu.', 44, 'lv', 12, 20, 'Vispārējā vidējā vai vidējā profesionālā izglītība', NULL, 1, 'afd1c271-6f4b-45f1-8d1b-ba17f9f0a631', '9cfb9a5a-4480-49ed-b018-babf2e4424b4', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('808096ac-ffdc-44f0-a90a-35977c816e52', 64, 'Studiju kursa ietvarā studējošais apgūst datorzinātņu būtību un pamatprincipus, izskata abstrakto skaitļojamo mašīnu realizāciju fiziskā ierīcē. Studējošais apgūst algoritmu veidošanas pamatus un vienkāršu algoritmu realizāciju programmēšanas valodā Python. 
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('a215efa2-b605-4923-a6f2-621e22d2532c', 32, 'Kursa mērķis ir tālāk pilnveidot studentu izpratni par IT angļu valodu daudzpusīgās tematiskās jomās un apgūt šajās jomās lietoto terminoloģiju un speciālo leksiku, spēt to atpazīt, saprast, sastatīt ar ekvivalentiem latviešu valodā un spēt to lietot mutvārdu un rakstveida saziņā atbilstoši angļu valodas lietošanas normām. Papildu mērķis – pilnveidot vispārējās jeb caurviju prasmes, īpašu uzmanību pievēršot (a) pašavadītas mācīšanās prasmju pilnveidei un (b) izziņai par savu iespējamo specializācijas jomu IT tirgū, papildus uzlabojot izpratni par uzņēmējdarbību IT jomā un ar to saistītos kontekstus un biznesa leksiku (mutvārdu un rakstveida komunikācijas ietvaros). ', '2026-05-03 10:43:27.227104', NULL, 'Studiju kursa ietvaros studenti – nodarbībās un patstāvīgi, grupās un individuāli - pilnveido darba tirgū nepieciešamās angļu valodas kompetences un vispārējās ar valodas lietojumu saistītās kompetences – dažāda veida funkcionālo tekstu uztveri un izveidi mutvārdos un rakstveidā, apgūstot un izmantojot nozares leksiku. ', 44, 'en', 4, 28, 'Sekmīgi apgūts kurss Angļu valoda I', NULL, 1, '1cba519a-59a7-4093-b3d8-2072685c1bf2', '8e9abc5b-9442-45f5-87c7-201ff0adb328', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('c2cb8133-dbca-42a5-82a2-defff0662094', 32, 'Studiju kursa ietvaros studenti – nodarbībās un patstāvīgi, grupās un individuāli - pilnveido darba tirgū nepieciešamās angļu valodas kompetences un vispārējās ar valodas lietojumu saistītās kompetences – dažāda veida funkcionālo tekstu uztveri un izveidi mutvārdos un rakstiski, apgūstot un izmantojot nozares leksiku. ', '2026-04-19 03:54:12.416887', NULL, 'Kursa mērķis ir pilnveidot studentu izpratni par IT angļu valodu dažādās tematiskās jomās un apgūt šajās jomās lietoto terminoloģiju un speciālo leksiku, spēt to atpazīt, saprast, sastatīt ar ekvivalentiem latviešu valodā un spēt to lietot mutvārdu un rakstveida saziņā atbilstoši angļu valodas lietošanas normām. Papildu mērķis – pilnveidot vispārējās jeb caurviju prasmes, īpašu uzmanību pievēršot (a) informācijas izguvei, apkopošanai, novērtēšanai un apstrādei, un analīzes apkopojuma/secinājumu pasniegšanai mutvārdos vai rakstiski dāžada veida funkcionālajos teikstos un (b) mutvārdu un rakstveida komunikācijai ar dažādu mērķauditoriju dažādu mērķu sasniegšanai.', 44, 'en', 0, 32, 'Vidusskolas angļu valodas eksāmenā iegūts pozitīvs vērtējums', NULL, 3, 'e3a130bc-54bf-428c-89a9-31805ef5803d', 'd290798e-7ee1-4e8f-946a-b9376b643208', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('18d2fd4d-3eed-4908-a313-26b6a375294a', 0, NULL, '2026-04-23 12:30:05.214628', NULL, NULL, 0, 'lv', NULL, NULL, NULL, NULL, NULL, 'e061eaa6-1678-40cc-a814-ad0616bd1d1d', '3ecf54a4-6764-4e5c-8b26-144a33bb17a5', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('b8e12532-459d-4dba-bcc8-f3385c06f0b5', 32, 'Lai ar programmēšanas (vai vismaz datora) palīdzību veiksmīgi risinātu problēmas, jāspēj tās formalizēt datoram saprotamā formā. Lai varētu labāk veikt šo formalizācijas procesu, tiek apskatīts algoritma jēdziens, tā biežākās attēlošanas formas kā arī metodoloģijas pēc kurām var salīdzināt dažādus algoritmus pēc to efektivitātes. Kursa ietvaros studenti zīmē blokshēmas, raksta pseidokodus, raksta programmu kodus kā arī aprēķina sarežģītības kārtas dažādiem algoritmiem.', '2026-05-02 23:57:17.898512', NULL, 'Kursa mērķis ir iepazīstināt studentus ar algoritma jēdzienu, tā sarežģītības novērtēšanu un biežāk izmantotajām algoritmu paradigmām.', 44, 'lv', 16, 16, 'Nav', NULL, 1, 'e89fd28f-d1d8-42da-b55f-72fcea77d27b', '8b8640e6-6986-41f0-ae03-38c93a54ec6a', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('f96e6a04-70cb-4822-af03-4eb0097f6e90', 35, 'Studiju kursā tiek apgūta procedūrorientētā programmēšana ar nelielu ieskatu objektorientētajā programmēšanā. Kursā tiek izmantota programmēšanas valoda C++, kas citu programmēšanas valodu starpā izceļas ar ātrdarbību un datora resursu taupīšanu. C++ izmanto, lai veidotu lietotnes, kuras ir ātras, efektīvi pārvalda datora sistēmas resursus un ir spējīgas risināt kritiskus uzdevumus, piemēram, iegulto sistēmu programmatūra, operētājsistēmas, pārlūkprogrammas, datorspēlēs un citas programmas.
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('8505bfaa-246c-4686-863f-6b02d4621703', 64, 'Studiju kursa ietvarā studējošais apgūst datorzinātņu būtību un pamatprincipus, izskata abstrakto skaitļojamo mašīnu realizāciju fiziskā ierīcē. Studējošais apgūst algoritmu veidošanas pamatus un vienkāršu algoritmu realizāciju programmēšanas valodā Python. 
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('11ac2e25-f7fd-43d0-8166-32eb7ed5f2d0', 32, 'Studiju kursā tiek apgūta procedūrorientētā programmēšana ar nelielu ieskatu objektorientētajā programmēšanā. Kursā tiek izmantota programmēšanas valoda C++, kas citu programmēšanas valodu starpā izceļas ar ātrdarbību un datora resursu taupīšanu. C++ izmanto, lai veidotu lietotnes, kuras ir ātras, efektīvi pārvalda datora sistēmas resursus un ir spējīgas risināt kritiskus uzdevumus, piemēram, iegulto sistēmu programmatūra, operētājsistēmas, pārlūkprogrammas, datorspēlēs un citas programmas.
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('c74bab0f-0045-45b3-8547-4e2131abce5a', 32, 'Studiju kursā tiek apgūta procedūrorientētā programmēšana ar nelielu ieskatu objektorientētajā programmēšanā. Kursā tiek izmantota programmēšanas valoda C++, kas citu programmēšanas valodu starpā izceļas ar ātrdarbību un datora resursu taupīšanu. C++ izmanto, lai veidotu lietotnes, kuras ir ātras, efektīvi pārvalda datora sistēmas resursus un ir spējīgas risināt kritiskus uzdevumus, piemēram, iegulto sistēmu programmatūra, operētājsistēmas, pārlūkprogrammas, datorspēlēs un citas programmas.
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('f26e2d96-3d76-4518-9c90-8b18b66c9b8c', 32, 'Studiju kursa ietvaros studenti – nodarbībās un patstāvīgi, grupās un individuāli - pilnveido darba tirgū nepieciešamās angļu valodas kompetences un vispārējās ar valodas lietojumu saistītās kompetences – dažāda veida funkcionālo tekstu uztveri un izveidi mutvārdos un rakstiski, apgūstot un izmantojot nozares leksiku. ', '2026-05-03 15:15:03.421987', NULL, 'Kursa mērķis ir pilnveidot studentu izpratni par IT angļu valodu dažādās tematiskās jomās un apgūt šajās jomās lietoto terminoloģiju un speciālo leksiku, spēt to atpazīt, saprast, sastatīt ar ekvivalentiem latviešu valodā un spēt to lietot mutvārdu un rakstveida saziņā atbilstoši angļu valodas lietošanas normām. Papildu mērķis – pilnveidot vispārējās jeb caurviju prasmes, īpašu uzmanību pievēršot (a) informācijas izguvei, apkopošanai, novērtēšanai un apstrādei, un analīzes apkopojuma/secinājumu pasniegšanai mutvārdos vai rakstiski dāžada veida funkcionālajos teikstos un (b) mutvārdu un rakstveida komunikācijai ar dažādu mērķauditoriju dažādu mērķu sasniegšanai.', 44, 'en', 0, 32, 'Vidusskolas angļu valodas eksāmenā iegūts pozitīvs vērtējums', NULL, 3, 'e3a130bc-54bf-428c-89a9-31805ef5803d', '272125c1-c4ca-4069-a48a-643798f2dff6', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('4ffc5cfe-068b-411a-8db5-d5fe753cbbc4', 32, 'Studiju kursa ietvaros studenti – nodarbībās un patstāvīgi, grupās un individuāli - pilnveido darba tirgū nepieciešamās angļu valodas kompetences un vispārējās ar valodas lietojumu saistītās kompetences – dažāda veida funkcionālo tekstu uztveri un izveidi mutvārdos un rakstiski, apgūstot un izmantojot nozares leksiku. ', '2026-05-03 15:17:53.175106', NULL, 'Kursa mērķis ir pilnveidot studentu izpratni par IT angļu valodu dažādās tematiskās jomās un apgūt šajās jomās lietoto terminoloģiju un speciālo leksiku, spēt to atpazīt, saprast, sastatīt ar ekvivalentiem latviešu valodā un spēt to lietot mutvārdu un rakstveida saziņā atbilstoši angļu valodas lietošanas normām. Papildu mērķis – pilnveidot vispārējās jeb caurviju prasmes, īpašu uzmanību pievēršot (a) informācijas izguvei, apkopošanai, novērtēšanai un apstrādei, un analīzes apkopojuma/secinājumu pasniegšanai mutvārdos vai rakstiski dāžada veida funkcionālajos teikstos un (b) mutvārdu un rakstveida komunikācijai ar dažādu mērķauditoriju dažādu mērķu sasniegšanai.', 44, 'en', 0, 32, 'Vidusskolas angļu valodas eksāmenā iegūts pozitīvs vērtējums', NULL, 3, 'e3a130bc-54bf-428c-89a9-31805ef5803d', '4b521113-27b1-4de2-8a36-1fcf45971beb', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('6d2d0040-b5fc-4eec-9202-4a3543035dc7', 32, 'Kurss sastāv no teorijas lekcijām, kas sniedz vispārīgu un aktuālu informāciju par svarīgākajām datora sastāvdaļām ar vēsturisko kontekstu un īpašu uzsvaru uz centrālā procesora darbības pamatprincipiem. Savukārt laboratorijas darbu ietvaros studenti apgūst tādas ar datorsistēmu uzturēšanu saistītas prasmes kā datora izjaukšana/salikšana, operētājsistēmu instalēšana, diska partīciju izveide un klonēšana, tīkla konfigurācija utt.', '2026-05-03 15:33:32.640926', NULL, 'Kursa mērķis ir sniegt vispārīgu informāciju par svarīgākajām datora sastāvdaļām – centrālo procesoru un tā darbības principiem, dažādiem atmiņas veidiem un citu svarīgāko perifēriju, kā arī apgūt praktiskas iemaņas darbā ar datorsistēmu uzturēšanu.', 44, 'lv', 12, 20, 'Vispārējā vidējā vai vidējā profesionālā izglītība', NULL, 1, 'afd1c271-6f4b-45f1-8d1b-ba17f9f0a631', 'ace4ee41-eaf0-4e9f-a6e1-a36fc7090b43', NULL, NULL) ON CONFLICT DO NOTHING;
