INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('27cb9e40-9048-4589-8566-ca9ac7f83481', 32, 'Lai ar programmēšanas (vai vismaz datora) palīdzību veiksmīgi risinātu problēmas, jāspēj tās formalizēt datoram saprotamā formā. Lai varētu labāk veikt šo formalizācijas procesu, tiek apskatīts algoritma jēdziens, tā biežākās attēlošanas formas kā arī metodoloģijas pēc kurām var salīdzināt dažādus algoritmus pēc to efektivitātes. Kursa ietvaros studenti zīmē blokshēmas, raksta pseidokodus, raksta programmu kodus kā arī aprēķina sarežģītības kārtas dažādiem algoritmiem.', '2026-05-14 12:42:02.408054', NULL, 'Kursa mērķis ir iepazīstināt studentus ar algoritma jēdzienu, tā sarežģītības novērtēšanu un biežāk izmantotajām algoritmu paradigmām.', 44, 'lv', 16, 16, 'Nav', NULL, 1, 'e89fd28f-d1d8-42da-b55f-72fcea77d27b', '501f14d9-0c38-4dc9-8ecc-bb02e6e73e64', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_info (id, academic_hours_total, annotation, created_at, deleted_at, goal, independent_work_hours, language, lecture_hours, pract_classes_hours, prerequisites_description, updated_at, assessment_form_id, course_id, course_version_id, created_by, updated_by) VALUES ('ca667a16-ae75-4347-b375-ee42766584a2', 32, 'Kursa mērķis ir tālāk pilnveidot studentu izpratni par IT angļu valodu daudzpusīgās tematiskās jomās un apgūt šajās jomās lietoto terminoloģiju un speciālo leksiku, spēt to atpazīt, saprast, sastatīt ar ekvivalentiem latviešu valodā un spēt to lietot mutvārdu un rakstveida saziņā atbilstoši angļu valodas lietošanas normām. Papildu mērķis – pilnveidot vispārējās jeb caurviju prasmes, īpašu uzmanību pievēršot (a) pašavadītas mācīšanās prasmju pilnveidei un (b) izziņai par savu iespējamo specializācijas jomu IT tirgū, papildus uzlabojot izpratni par uzņēmējdarbību IT jomā un ar to saistītos kontekstus un biznesa leksiku (mutvārdu un rakstveida komunikācijas ietvaros). ', '2026-05-21 00:09:28.880385', NULL, 'Studiju kursa ietvaros studenti – nodarbībās un patstāvīgi, grupās un individuāli - pilnveido darba tirgū nepieciešamās angļu valodas kompetences un vispārējās ar valodas lietojumu saistītās kompetences – dažāda veida funkcionālo tekstu uztveri un izveidi mutvārdos un rakstveidā, apgūstot un izmantojot nozares leksiku. ', 44, 'en', 4, 28, 'Sekmīgi apgūts kurss Angļu valoda I', NULL, 1, '1cba519a-59a7-4093-b3d8-2072685c1bf2', '0ce8c9ff-547b-463b-ac7d-c27d0ab4a6f0', NULL, NULL) ON CONFLICT DO NOTHING;
