INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (1, '2026-04-04 20:21:14.879817', 'lv', 1, '<p>Algoritms. Programma. Programmēšanas paradigmas. <u>Programmēšanas </u>valodas. Programmēšanas valodu attīstības tendences.&nbsp;</p><p></p><p></p>', 'Ievads', NULL, 'c74bab0f-0045-45b3-8547-4e2131abce5a', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (20, '2026-05-03 00:01:33.338818', 'lv', 8, NULL, 'Algoritmu paradigmas', NULL, 'b8e12532-459d-4dba-bcc8-f3385c06f0b5', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (22, '2026-05-03 00:24:56.298133', 'lv', 1, '<p>Skaitīšanas sistēmas, negatīvu skaitļu reprezentācija binārajā sistēmā, datorsistēmu veidi, iegultās sistēmas, datoru paaudzes, tipiska datora uzbūve</p><p></p>', 'Ievads', NULL, '884291a6-0809-44cc-826c-d3c28ab24b39', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (23, '2026-05-03 00:24:56.333701', 'lv', 2, '<p>Teorētiska CPU uzbūve, asemblervaloda, loģiskie elementi, Būla algebra, summators, Intel 8086 CPU arhitektūra un instrukciju formāti; Fon Neimaņa/Hārvardas un RISC/CISC arhitektūras, atšķirības starp mikroprocesoru un mikrokontrolieri; CPU veiktspēja; CPU ražotāji</p><p></p>', 'Centrālais procesors (CPU)', NULL, '884291a6-0809-44cc-826c-d3c28ab24b39', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (4, '2026-04-05 13:41:55.806085', 'lv', 2, '<p><strong>Konstantes</strong>. Operatori. Operatoru prioritātes. Ievades/izvade, izmantojot standarta ierīces. Komentāri. C++ programmēšanas labā prakse.</p>', 'Mainīgā jēdziens, pamata jeb iebūvētie datu tipi', NULL, 'c74bab0f-0045-45b3-8547-4e2131abce5a', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (2, '2026-04-04 20:21:14.962521', 'lv', 3, '<p>Valodas standarti. Programmu izstrādes vides. C++ programmas struktūra. Programmas kompilācija un izpilde, kļūdu konstatēšana un labošana. Sintakse un semantika.&nbsp;</p>', 'Programmēšanas valoda C++', NULL, 'c74bab0f-0045-45b3-8547-4e2131abce5a', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (36, '2026-05-03 00:45:21.993628', 'lv', 11, NULL, 'Abstraktās skaitļojamās mašīnas un reālie datori', NULL, '808096ac-ffdc-44f0-a90a-35977c816e52', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (24, '2026-05-03 00:24:56.343927', 'lv', 3, '<p>Atmiņas mērvienības (SI, IEC un JEDEC sistēmas), cietais disks (HDD un SSD), zibatmiņa (flash),partīcijas, failu sistēmas, BIOS/MBR un UEFI/GPT, biežāk izmantotie RAID (redundant array of independent disks) līmeņi; statiskā un dinamiskā brīvpiekļuves atmiņa (RAM), kešatmiņa</p><p></p>', 'Atmiņa', NULL, '884291a6-0809-44cc-826c-d3c28ab24b39', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (27, '2026-05-03 00:24:56.374433', 'lv', 6, '<p>ATX standarts, PCI un PCIe, grafiskie procesori (GPU), pamatlietas par tīklu un TCP/IP protokolu kopu</p><p></p>', 'Perifērija un tīkls', NULL, '884291a6-0809-44cc-826c-d3c28ab24b39', NULL, NULL) ON CONFLICT DO NOTHING;
