INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (45, '2026-05-03 00:45:22.111044', 'lv', 26, NULL, 'Failu kārtošana. Saplūšanas pamatprocedūra. Tieša failu saplūšana.', NULL, '808096ac-ffdc-44f0-a90a-35977c816e52', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (98, '2026-05-03 12:40:56.955137', 'lv', 1, '<p>Algoritms. Programma. Programmēšanas paradigmas. <u>Programmēšanas </u>valodas. Programmēšanas valodu attīstības tendences.&nbsp;</p><p></p><p></p>', 'Ievads', NULL, '11ac2e25-f7fd-43d0-8166-32eb7ed5f2d0', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (99, '2026-05-03 12:40:56.968966', 'lv', 2, '<p><strong>Konstantes</strong>. Operatori. Operatoru prioritātes. Ievades/izvade, izmantojot standarta ierīces. Komentāri. C++ programmēšanas labā prakse.</p>', 'Mainīgā jēdziens, pamata jeb iebūvētie datu tipi', NULL, '11ac2e25-f7fd-43d0-8166-32eb7ed5f2d0', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (100, '2026-05-03 12:40:56.971046', 'lv', 3, '<p>Valodas standarti. Programmu izstrādes vides. C++ programmas struktūra. Programmas kompilācija un izpilde, kļūdu konstatēšana un labošana. Sintakse un semantika.&nbsp;</p>', 'Programmēšanas valoda C++', NULL, '11ac2e25-f7fd-43d0-8166-32eb7ed5f2d0', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (41, '2026-05-03 00:45:22.05961', 'lv', 19, NULL, 'Aritmētiski- loģiska ierīce. Procesors.', NULL, '808096ac-ffdc-44f0-a90a-35977c816e52', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (101, '2026-05-03 12:40:56.973895', 'lv', 4, NULL, 'Attieksmes un loģiskie operatori. Zarošanās priekšraksti.', NULL, '11ac2e25-f7fd-43d0-8166-32eb7ed5f2d0', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (102, '2026-05-03 12:40:56.976261', 'lv', 5, NULL, 'Atkārtojuma priekšraksti.', NULL, '11ac2e25-f7fd-43d0-8166-32eb7ed5f2d0', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (103, '2026-05-03 12:40:56.978395', 'lv', 6, '<p>C++ standarta bibliotēkas funkcijas. Funkciju definēšana (prototips un implementēšana) . Funkciju pārslogošana. Mainīgā tvērums.</p>', 'Funkcijas jēdziens', NULL, '11ac2e25-f7fd-43d0-8166-32eb7ed5f2d0', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (104, '2026-05-03 12:40:56.981305', 'lv', 7, '<p>Daudzdimensiju masīvi. Masīvi kā funkciju parametri. Programmēšanas uzdevumi.&nbsp;</p>', 'Masīvi, to izveidošana un lietošana', NULL, '11ac2e25-f7fd-43d0-8166-32eb7ed5f2d0', NULL, NULL) ON CONFLICT DO NOTHING;
