INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (115, '2026-05-03 15:33:32.645792', 'lv', 1, '<p>Skaitīšanas sistēmas, negatīvu skaitļu reprezentācija binārajā sistēmā, datorsistēmu veidi, iegultās sistēmas, datoru paaudzes, tipiska datora uzbūve</p><p></p>', 'Ievads', NULL, '6d2d0040-b5fc-4eec-9202-4a3543035dc7', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (116, '2026-05-03 15:33:32.654789', 'lv', 2, '<p>Teorētiska CPU uzbūve, asemblervaloda, loģiskie elementi, Būla algebra, summators, Intel 8086 CPU arhitektūra un instrukciju formāti; Fon Neimaņa/Hārvardas un RISC/CISC arhitektūras, atšķirības starp mikroprocesoru un mikrokontrolieri; CPU veiktspēja; CPU ražotāji</p><p></p>', 'Centrālais procesors (CPU)', NULL, '6d2d0040-b5fc-4eec-9202-4a3543035dc7', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (117, '2026-05-03 15:33:32.656922', 'lv', 3, '<p>Atmiņas mērvienības (SI, IEC un JEDEC sistēmas), cietais disks (HDD un SSD), zibatmiņa (flash),partīcijas, failu sistēmas, BIOS/MBR un UEFI/GPT, biežāk izmantotie RAID (redundant array of independent disks) līmeņi; statiskā un dinamiskā brīvpiekļuves atmiņa (RAM), kešatmiņa</p><p></p>', 'Atmiņa', NULL, '6d2d0040-b5fc-4eec-9202-4a3543035dc7', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (118, '2026-05-03 15:33:32.658514', 'lv', 4, '<p>Ātrdarbības testi un klonēšana ar CloneZilla un gparted</p>', 'Cietie diski (testi un klonēšana)', NULL, '6d2d0040-b5fc-4eec-9202-4a3543035dc7', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (119, '2026-05-03 15:33:32.660096', 'lv', 5, '<p>Partīcijas izveide, formatēšana un RAID (redundant array of independent disks)  izveide</p>', 'Cietie diski (partīcijas, formatēšana, RAID)', NULL, '6d2d0040-b5fc-4eec-9202-4a3543035dc7', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (120, '2026-05-03 15:33:32.661703', 'lv', 6, '<p>ATX standarts, PCI un PCIe, grafiskie procesori (GPU), pamatlietas par tīklu un TCP/IP protokolu kopu</p><p></p>', 'Perifērija un tīkls', NULL, '6d2d0040-b5fc-4eec-9202-4a3543035dc7', NULL, NULL) ON CONFLICT DO NOTHING;
INSERT INTO public.course_content (id, created_at, language, sequence_number, topic_description, topic_title, updated_at, course_info_id, created_by, updated_by) VALUES (121, '2026-05-03 15:33:32.664375', 'lv', 7, NULL, 'Datora darbības pārbaude un labošana', NULL, '6d2d0040-b5fc-4eec-9202-4a3543035dc7', NULL, NULL) ON CONFLICT DO NOTHING;
